import hashlib

def secured_hash(string):
    # Encode the string to bytes
    encoded_string = string.encode('utf-8')
    
    # Create SHA-256 hash object and get the hexadecimal digest
    hash_object = hashlib.sha256(encoded_string)
    hex_digest = hash_object.hexdigest()
    
    # Convert the hexadecimal digest to an integer
    hash_int = int(hex_digest, 16)
    
    # Return value between 0 and 999
    return hash_int % 1000


